simple_procs = {
    "Robotic Sigmoid Colectomy": None,  # already covered in Q2
    "Robotic Total Abdominal Colectomy": [
        {"question": "What is the operative advantage of robotic total colectomy over laparoscopic?", "answer": "Multi-quadrant dissection with a single docking (newer Xi platform rotates arms), enhanced 3D visualization for splenic/hepatic flexure mobilization, and reduced conversion rates in obese patients. The Si platform required re-docking; the Xi platform operates across all quadrants."},
        {"question": "What vascular pedicles are divided during robotic total colectomy?", "answer": "Ileocolic, right colic (if present), middle colic (right and left branches), and IMA. All from the SMA/IMA system. The marginal artery is entirely removed with the specimen. Both ureters must be identified before pedicle ligation."},
        {"question": "What is the anastomosis after robotic total colectomy?", "answer": "Ileorectal anastomosis (IRA) -- typically side-to-end stapled or hand-sewn. The rectum is divided at the sacral promontory. The ileal-rectal anastomosis heals well due to the ileum's robust SMA blood supply and the rectum's middle/inferior rectal arteries."},
        {"question": "What is the indication for total colectomy in FAP versus Lynch syndrome?", "answer": "FAP: total proctocolectomy with IPAA (entire colon and rectum at cancer risk). Lynch syndrome: total colectomy with IRA (rectum can be surveilled, lower morbidity). The distinction matters because FAP has near-100% rectal cancer risk while Lynch has lower rectal involvement."},
        {"question": "What functional outcome difference exists between IRA and IPAA?", "answer": "IRA: 3-5 stools/day (better function, rectum provides reservoir). IPAA: 5-8 stools/day (no rectal reservoir, but eliminates rectal cancer risk). IRA patients need lifelong rectal surveillance with annual proctoscopy for new polyps/cancer."}
    ],
    "Ileal Pouch-Anal Anastomosis Revision": [
        {"question": "What are the most common indications for IPAA revision?", "answer": "Chronic pouchitis refractory to antibiotics, pouch-vaginal fistula, pouch stricture, pouch leak, and Crohn's disease misdiagnosis (originally thought to be UC). Complete pouch excision with new pouch construction is performed in 40-50% of revisions."},
        {"question": "What determines whether a redo pouch can be created versus conversion to permanent ileostomy?", "answer": "Adequate remaining small bowel length (must have enough ileum for a new pouch + reach the anus), absence of Crohn's disease, adequate sphincter function, and patient motivation. If total small bowel is <200cm, a new pouch may cause short bowel syndrome."},
        {"question": "What is the blood supply to the redo pouch?", "answer": "SMA branches via the ileal arcade. The new pouch must be created from fresh ileum proximal to the previous pouch site. The mesentery may be scarred from prior surgery, making reach to the pelvis challenging. Mesenteric lengthening techniques are often required."},
        {"question": "What is the success rate of IPAA revision?", "answer": "60-70% functional success (vs 90-95% for primary IPAA). Higher failure rates due to scarred pelvis, shorter mesentery, and underlying disease (especially if Crohn's disease is discovered). Patients must be counseled that permanent ileostomy remains a possibility."},
        {"question": "What is the most important preoperative workup before IPAA revision?", "answer": "Pouchoscopy with biopsy (rule out Crohn's, CMV, C. diff), EUA with probe (identify fistula tracts), pelvic MRI (pouch anatomy, abscess, fistula), anorectal manometry (sphincter function), and small bowel evaluation (CT enterography to assess remaining bowel and rule out Crohn's)."}
    ],
    "Coloanal Anastomosis": [
        {"question": "What is the embryologic junction at which a coloanal anastomosis is performed?", "answer": "The anal canal above the dentate line -- where hindgut-derived columnar epithelium meets ectoderm-derived squamous epithelium. The anastomosis is hand-sewn between the colon and the anal canal at or just above the dentate line."},
        {"question": "When is coloanal anastomosis preferred over low stapled colorectal anastomosis?", "answer": "When the tumor is within 1-2cm of the dentate line and a stapled anastomosis cannot achieve adequate distal margin. The rectum is excised to the pelvic floor, and the colon is hand-sewn to the anal canal through a transanal approach."},
        {"question": "What is the blood supply to the colon at the level of a coloanal anastomosis?", "answer": "The proximal colon depends on its mesenteric blood supply (IMA branches or marginal artery). The anal canal is supplied by inferior rectal arteries (from internal pudendal). The anastomosis heals by granulation between these two vascular territories."},
        {"question": "What functional outcome is expected after coloanal anastomosis?", "answer": "LARS (Low Anterior Resection Syndrome) is nearly universal: 8-15 stools/day initially, improving to 4-8/day at 1 year. A colonic J-pouch (6-8cm) or transverse coloplasty reduces stool frequency. Nocturnal incontinence: 20-40%. Most patients need temporary diverting ileostomy (reversed at 8-12 weeks)."},
        {"question": "What is an intersphincteric resection (ISR)?", "answer": "Dissection between the internal and external anal sphincters, removing the internal sphincter with the specimen while preserving the external sphincter for continence. Allows ultra-low coloanal anastomosis for tumors at or just above the dentate line. Continence outcomes are worse than standard coloanal but better than APR (permanent stoma)."}
    ],
    "Ileostomy Reversal": [
        {"question": "What preoperative study is mandatory before ileostomy reversal?", "answer": "Water-soluble contrast enema (Gastrografin) to confirm anastomotic integrity, absence of stricture, and distal segment patency. Also endoscopy if cancer was the original indication. Never reverse if there is a leak or significant stricture."},
        {"question": "What is the technique for local ileostomy reversal?", "answer": "Circumferential skin incision, mobilization from the fascial defect, resection of the stoma segment (fresh bowel edges), and either hand-sewn or stapled side-to-side functional end-to-end reanastomosis through the stoma wound. The fascial defect is closed primarily."},
        {"question": "What is the blood supply to the reanastomosed ileum?", "answer": "SMA via ileal branches. The stoma segment is resected back to healthy, well-perfused bowel with brisk bleeding at the cut edges. The mesentery must be intact without twist."},
        {"question": "What is the most common complication after ileostomy reversal?", "answer": "Small bowel obstruction (5-10%) -- the most common cause of readmission. Adhesions at the stoma site and internal herniation through the mesenteric defect are the usual mechanisms. Wound infection (5-15%), anastomotic leak (1-3%), and prolonged ileus (5-10%)."},
        {"question": "What is the optimal timing for ileostomy reversal?", "answer": "8-12 weeks after the index operation (allows inflammation to resolve and anastomosis to mature). After neoadjuvant chemoradiation for rectal cancer, many surgeons wait 12-16 weeks. Confirm completion of adjuvant chemotherapy before reversal when applicable."}
    ],
    "Colostomy Reversal": [
        {"question": "How does Hartmann's reversal differ technically from loop colostomy reversal?", "answer": "Hartmann's reversal requires formal laparotomy: adhesiolysis, identification of the rectal stump (often retracted and scarred), mobilization of the proximal colon, and colorectal reanastomosis. Loop colostomy reversal can often be done locally through the stoma site. Hartmann's reversal has significantly higher morbidity."},
        {"question": "What is the blood supply concern when mobilizing the retracted rectal stump?", "answer": "The rectal stump depends on middle and inferior rectal arteries (from internal iliac system). In a scarred, previously irradiated pelvis, the stump may have compromised blood supply. Fresh bleeding at the stump transection line must be confirmed before anastomosis."},
        {"question": "What is the leak rate after Hartmann's reversal?", "answer": "4-16% -- higher than primary colorectal anastomosis due to: scarred tissue, poor blood supply, difficult pelvic dissection, and tension. Overall morbidity: 25-50%. Mortality: 1-4%."},
        {"question": "What percentage of Hartmann's patients undergo reversal?", "answer": "Only 40-60%. Factors preventing reversal: advanced age, comorbidities, recurrent cancer, patient preference, and surgeon reluctance. This is an important counseling point -- many 'temporary' Hartmann's become permanent."},
        {"question": "What is the laparoscopic approach to Hartmann's reversal?", "answer": "Laparoscopic adhesiolysis, identification of the rectal stump (often with flexible sigmoidoscopy transanally to guide pelvic dissection), mobilization of the proximal colon, and circular stapled colorectal anastomosis. Laparoscopic approach reduces wound complications and hospital stay compared to open but requires experience with pelvic adhesiolysis."}
    ],
}
