more_procs = {
    "Stapled Hemorrhoidopexy (PPH)": [
        {"question": "What is the principle of stapled hemorrhoidopexy versus excisional hemorrhoidectomy?", "answer": "PPH (Procedure for Prolapse and Hemorrhoids) excises a circumferential ring of rectal mucosa above the hemorrhoidal cushions, lifting and repositioning them. It does NOT excise the hemorrhoids themselves -- it disrupts their arterial supply and reduces prolapse by lifting the cushions back into the anal canal."},
        {"question": "What landmark must the staple line remain above?", "answer": "The dentate line -- the staple line must be at least 2cm above the dentate line (in the insensate rectal mucosa). Stapling at or below the dentate line causes excruciating pain, chronic proctalgia, and urgency. This is the most common technical error."},
        {"question": "What is the blood supply disrupted by stapled hemorrhoidopexy?", "answer": "The superior rectal artery branches that supply the hemorrhoidal cushions are transected in the circumferential mucosal/submucosal ring. This reduces arterial inflow to the cushions, causing their regression. The circular stapler also compresses the submucosal venous plexus."},
        {"question": "What is the most feared complication of PPH?", "answer": "Rectal perforation/pelvic sepsis (rare but potentially fatal -- 0.1%). Also: bleeding from the staple line (3-5%), staple line stricture (2-5%), urgency/tenesmus (5-15%), and chronic pelvic pain from suture/staple granuloma. Recurrence rate: 5-15% (higher than excisional hemorrhoidectomy at long-term follow-up)."},
        {"question": "Has stapled hemorrhoidopexy fallen out of favor?", "answer": "Yes, largely. The eTHoS trial (2016): PPH had higher recurrence and re-intervention rates than traditional excisional hemorrhoidectomy at 1 year, despite less early postoperative pain. Most colorectal surgeons now prefer excisional hemorrhoidectomy or newer techniques (THD/HAL -- transanal hemorrhoidal dearterialization)."}
    ],
    "TAMIS (Transanal Minimally Invasive Surgery)": [
        {"question": "What platform is used for TAMIS?", "answer": "A single-port transanal access platform (GelPOINT Path) inserted into the anal canal, with standard laparoscopic instruments and CO2 insufflation. It provides a pneumorectum for visualization and precise excision of rectal lesions up to 15cm from the anal verge."},
        {"question": "What layers of the rectal wall are excised in a TAMIS full-thickness excision?", "answer": "Mucosa, submucosa, muscularis propria, and perirectal fat. The defect is closed primarily with absorbable suture. Full-thickness excision is required for adequate staging of T1 rectal cancers. Submucosal excision alone cannot exclude muscle invasion."},
        {"question": "What is the blood supply to the rectum at the TAMIS excision site?", "answer": "Superior, middle, and inferior rectal arteries via the submucosal plexus. Electrocautery controls the submucosal vessels during excision. Full-thickness excision may encounter mesorectal vessels requiring direct control."},
        {"question": "What are the indications and contraindications for TAMIS?", "answer": "Indications: benign polyps >2cm not amenable to endoscopic removal, selected T1 rectal cancers (favorable histology), and rectal biopsies. Contraindications: T2+ cancer (needs radical resection), lesions >50% circumference, lesions >15cm from anal verge, and poor sphincter tone (platform won't seal)."},
        {"question": "How does TAMIS compare to TEM (Transanal Endoscopic Microsurgery)?", "answer": "TAMIS uses disposable single-port platforms with standard laparoscopic instruments (cost-effective, widely available). TEM uses a specialized rigid operating rectoscope (expensive, requires dedicated equipment). Oncologic outcomes are equivalent. TAMIS has largely replaced TEM in most practices."}
    ],
    "Laparoscopic Ventral Mesh Rectopexy": [
        {"question": "What is the anatomy of rectal prolapse that ventral mesh rectopexy corrects?", "answer": "Full-thickness intussusception of the rectum (internal or external prolapse) due to loss of posterior fixation (Waldeyer's fascia) and deep pouch of Douglas. VMR lifts the anterior rectum with mesh from the level of the rectovaginal septum to the sacral promontory, obliterating the deep cul-de-sac."},
        {"question": "Why is the mesh placed ANTERIORLY rather than posteriorly?", "answer": "Posterior mesh (Wells, Ripstein) caused severe constipation from circumferential wrapping and posterior fibrosis. Anterior-only (ventral) mesh avoids posterior dissection, preserving the lateral ligaments and autonomic nerves. D'Hoore's VMR technique has lower constipation and recurrence rates."},
        {"question": "What is the blood supply concern with mesh placement on the anterior rectum?", "answer": "The mesh is sutured to the anterior rectal wall muscularis (NOT through full thickness). The middle rectal arteries enter laterally and must be preserved. The anterior dissection stays in the rectovaginal septum, avoiding the lateral vascular/nerve pedicles."},
        {"question": "What mesh material is used, and what is the erosion risk?", "answer": "Biologic mesh (porcine/bovine dermis) or lightweight synthetic (polypropylene). Mesh erosion into the rectum or vagina: <1% with biologic, 2-5% with synthetic. Most surgeons prefer biologic mesh to minimize erosion risk, especially in women where the mesh lies between rectum and vagina."},
        {"question": "What is the recurrence rate after laparoscopic ventral mesh rectopexy?", "answer": "5-10% at 5 years (lower than suture rectopexy). Functional outcomes: constipation improves in 60-80%, incontinence improves in 50-70%. VMR is now the preferred surgical approach for full-thickness rectal prolapse in many centers."}
    ],
    "Rubber Band Ligation of Hemorrhoids": [
        {"question": "At what level are the bands applied, and why is this critical?", "answer": "1-2cm ABOVE the dentate line on the insensate rectal mucosa. Below the dentate line: somatic innervation causes excruciating pain. The band strangulates the hemorrhoidal tissue, which sloughs in 5-7 days. Maximum 1-2 bands per session to reduce complication risk."},
        {"question": "What is the blood supply being interrupted by banding?", "answer": "The superior rectal artery terminal branches supplying the hemorrhoidal cushion. The band causes ischemic necrosis of the banded tissue, which sloughs leaving an ulcer that heals with scarring, fixing the mucosa to the underlying muscle and preventing prolapse."},
        {"question": "What is the most feared complication of rubber band ligation?", "answer": "Pelvic sepsis (0.05-0.1%) -- rare but potentially fatal. Presents with fever, perianal pain, urinary retention, and septic shock 3-10 days after banding. Caused by full-thickness necrosis extending into the perirectal space. Requires emergent debridement and broad-spectrum antibiotics. Immunosuppressed patients are at highest risk."},
        {"question": "What Goligher grades respond best to rubber band ligation?", "answer": "Grade I-II (and selected Grade III). Grade IV and thrombosed external hemorrhoids are NOT candidates for banding. Success rate: 60-80% at 5 years. 20-30% of patients need repeat banding. It is the most effective office procedure for internal hemorrhoids."},
        {"question": "What are the contraindications to rubber band ligation?", "answer": "Anticoagulation (high bleeding risk), external hemorrhoids (somatic pain), grade IV prolapse (too bulky), active proctitis/IBD, immunosuppression (sepsis risk), and pregnancy. Relative: coagulopathy, portal hypertension with rectal varices (masquerading as hemorrhoids -- banding varices causes massive hemorrhage)."}
    ],
    "Anal Sphincteroplasty (Anal Sphincter Repair)": [
        {"question": "What is the anatomy of the external anal sphincter that is repaired?", "answer": "A striated muscle complex with three parts (deep, superficial, subcutaneous) forming a cylindrical sleeve around the anal canal. Obstetric injury (3rd/4th degree tear) most commonly disrupts the anterior sphincter, creating a gap that weakens the continence mechanism. The internal sphincter (smooth muscle) provides 70-80% of resting tone."},
        {"question": "What is the 'overlap' repair technique?", "answer": "The scarred ends of the external sphincter are identified, mobilized, and overlapped (rather than approximated end-to-end). The overlap creates a wider sphincter ring and is secured with mattress sutures. Overlap repair has better continence outcomes (60-80%) than direct end-to-end repair (40-60%) at 5 years."},
        {"question": "What is the blood supply to the external sphincter that must be preserved?", "answer": "Inferior rectal artery (from internal pudendal). The pudendal nerve (S2-S4) provides motor innervation -- if the nerve is damaged (pudendal neuropathy from chronic stretch/obstetric injury), sphincteroplasty may fail despite anatomic repair because the muscle cannot contract."},
        {"question": "What preoperative evaluation is needed before sphincteroplasty?", "answer": "Endoanal ultrasound (defines the sphincter defect location and extent), anorectal manometry (measures resting and squeeze pressures), pudendal nerve terminal motor latency (PNTML -- if prolonged, suggests neuropathy and worse surgical outcomes), and defecography/MRI (exclude prolapse, rectocele)."},
        {"question": "What is the long-term durability of sphincteroplasty?", "answer": "Initial success: 60-80% improvement in continence. However, results deteriorate over time: only 40-50% maintain good continence at 5-10 years. Sacral nerve stimulation (SNS/InterStim) is now an alternative for fecal incontinence that does not require intact sphincter anatomy and has more durable results (70-80% at 5 years)."}
    ],
    "LIFT Procedure (Ligation of Intersphincteric Fistula Tract)": [
        {"question": "What is the anatomic basis of the LIFT procedure?", "answer": "The LIFT exploits the intersphincteric space (between the internal and external sphincter) where most cryptoglandular fistulas transit. An incision in the intersphincteric groove identifies the fistula tract, which is ligated and divided. This closes the internal opening without cutting through any sphincter muscle."},
        {"question": "Why is LIFT considered a sphincter-sparing procedure?", "answer": "No sphincter muscle is divided -- the tract is ligated in the intersphincteric plane. This preserves both the internal sphincter (resting tone) and external sphincter (squeeze pressure). Incontinence risk: <1%, compared to 10-40% for fistulotomy of trans-sphincteric fistulas."},
        {"question": "What is the blood supply to the intersphincteric space?", "answer": "Terminal branches of the inferior rectal artery and the intersphincteric arterial plexus. The intersphincteric space is relatively avascular compared to the sphincter muscles themselves, making dissection in this plane relatively bloodless."},
        {"question": "What is the success rate of LIFT?", "answer": "60-75% primary healing. Failure (persistent fistula): 25-40%, usually from incomplete tract ligation or unrecognized secondary tracts. Success improves with: proper patient selection (trans-sphincteric fistulas, not intersphincteric), complete ligation with suture (not clip), and addition of a bioprosthetic plug in the external tract."},
        {"question": "What are the alternatives to LIFT for complex trans-sphincteric fistulas?", "answer": "Advancement flap (endorectal or anodermal -- 60-70% success), VAAFT (video-assisted anal fistula treatment), FiLaC (fistula laser closure), injection of stem cells/fibrin glue (30-50%), and long-term draining seton. For Crohn's fistulas: anti-TNF therapy (infliximab) + seton is the standard first-line approach."}
    ],
}
